type HslColor = { h: number; s: number; l: number };

function clamp01(value: number): number {
  return Math.max(0, Math.min(1, value));
}

function clampHue(value: number): number {
  const mod = value % 360;
  return mod < 0 ? mod + 360 : mod;
}

function hexToHsl(hex: string): HslColor | null {
  const normalized = hex.trim().replace('#', '');
  if (!/^[0-9a-fA-F]{6}$/.test(normalized)) return null;
  const r = parseInt(normalized.slice(0, 2), 16) / 255;
  const g = parseInt(normalized.slice(2, 4), 16) / 255;
  const b = parseInt(normalized.slice(4, 6), 16) / 255;
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  const delta = max - min;
  const l = (max + min) / 2;
  if (delta === 0) return { h: 0, s: 0, l };
  const s = delta / (1 - Math.abs(2 * l - 1));
  let h = 0;
  if (max === r) h = ((g - b) / delta) % 6;
  else if (max === g) h = (b - r) / delta + 2;
  else h = (r - g) / delta + 4;
  return { h: clampHue(h * 60), s: clamp01(s), l: clamp01(l) };
}

function hslToHex(color: HslColor): string {
  const h = clampHue(color.h);
  const s = clamp01(color.s);
  const l = clamp01(color.l);
  const c = (1 - Math.abs(2 * l - 1)) * s;
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
  const m = l - c / 2;
  let r = 0;
  let g = 0;
  let b = 0;
  if (h < 60) [r, g, b] = [c, x, 0];
  else if (h < 120) [r, g, b] = [x, c, 0];
  else if (h < 180) [r, g, b] = [0, c, x];
  else if (h < 240) [r, g, b] = [0, x, c];
  else if (h < 300) [r, g, b] = [x, 0, c];
  else [r, g, b] = [c, 0, x];
  const toHex = (v: number) => Math.round((v + m) * 255).toString(16).padStart(2, '0');
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
}

function CalendarColorPicker({
  value,
  disabled,
  onChange,
}: {
  value: string;
  disabled: boolean;
  onChange: (nextHex: string) => void;
}) {
  const [hsl, setHsl] = useState<HslColor>(() => hexToHsl(value) ?? { h: 210, s: 0.54, l: 0.5 });
  const [open, setOpen] = useState(false);
  const paletteRef = useRef<HTMLDivElement>(null);

  const applyHsl = (next: HslColor) => {
    setHsl(next);
    onChange(hslToHex(next));
  };

  const updateFromPalettePointer = (clientX: number, clientY: number) => {
    const rect = paletteRef.current?.getBoundingClientRect();
    if (!rect) return;
    const s = clamp01((clientX - rect.left) / rect.width);
    const l = clamp01(1 - (clientY - rect.top) / rect.height);
    applyHsl({ ...hsl, s, l });
  };

  const startPaletteDrag = (event: React.PointerEvent<HTMLDivElement>) => {
    if (disabled) return;
    (event.currentTarget as HTMLDivElement).setPointerCapture(event.pointerId);
    updateFromPalettePointer(event.clientX, event.clientY);
  };

  return (
    <div className={styles.colorPicker}>
      <div className={styles.colorControlsRowCompact}>
        <div className={styles.colorSwatch} style={{ backgroundColor: hslToHex(hsl) }} />
        <input
          type="text"
          className={styles.input}
          value={value}
          readOnly={disabled}
          placeholder="#3b82c4"
          onChange={(e) => {
            const next = e.target.value;
            onChange(next);
            const parsed = hexToHsl(next);
            if (parsed) setHsl(parsed);
          }}
        />
        <Button type="button" className={styles.colorPickerToggleBtn} disabled={disabled} onClick={() => setOpen((v) => !v)}>
          <Pipette size={16} aria-hidden />
        </Button>
      </div>
      {open ? (
        <>
          <div
            ref={paletteRef}
            className={`${styles.colorPalette} ${disabled ? styles.colorPaletteDisabled : ''}`}
            style={{ backgroundColor: `hsl(${hsl.h} 100% 50%)` }}
            onPointerDown={startPaletteDrag}
            onPointerMove={(event) => {
              if (!disabled && event.buttons === 1) updateFromPalettePointer(event.clientX, event.clientY);
            }}
          >
            <span
              className={styles.colorPickerThumb}
              style={{ left: `${hsl.s * 100}%`, top: `${(1 - hsl.l) * 100}%` }}
            />
          </div>
          <div className={styles.colorControlsRow}>
            <input
              type="range"
              min={0}
              max={360}
              value={Math.round(hsl.h)}
              disabled={disabled}
              className={styles.colorHueSlider}
              onChange={(event) => applyHsl({ ...hsl, h: Number(event.target.value) })}
            />
          </div>
        </>
      ) : null}
    </div>
  );
}

export function StudentProfileTab({
  student,
  onChange,
  canEdit,
  viewerRole,
  onSave,
}: {
  student: MockStudent;
  onChange: (next: MockStudent) => void;
  canEdit: boolean;
  viewerRole: UserRole;
  onSave: () => void;
}) {
  const isStudentViewer = viewerRole === USER_ROLE.student.id;
  const isTeacherViewer = viewerRole === USER_ROLE.teacher.id;
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Full name</label>
          <Field className={styles.input} value={student.fullName} readOnly={!canEdit} onChange={(e) => onChange({ ...student, fullName: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Email</label>
          <Field className={styles.input} value={student.email} readOnly={!canEdit} onChange={(e) => onChange({ ...student, email: e.target.value })} />
        </div>
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Level</label>
            <AdaptiveSelect
              className={styles.input}
              value={String(student.proficiencyLevelId)}
              readOnly={!canEdit}
              onChange={(e) =>
                onChange({
                  ...student,
                  proficiencyLevelId: Number(e.target.value) as ProficiencyLevelId,
                })
              }
            >
              {(Object.keys(PROFICIENCY_LEVEL) as (keyof typeof PROFICIENCY_LEVEL)[]).map((key) => {
                const L = PROFICIENCY_LEVEL[key];
                return (
                  <option key={L.id} value={L.id}>
                    {L.code} — {L.label}
                  </option>
                );
              })}
            </AdaptiveSelect>
          </div>
        ) : null}
        {!isTeacherViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Phone</label>
            <Field className={styles.input} value={student.phone} readOnly={!canEdit} onChange={(e) => onChange({ ...student, phone: e.target.value })} />
          </div>
        ) : null}
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Timezone</label>
          <AdaptiveSelect
            className={styles.input}
            value={String(student.timezoneId)}
            readOnly={!canEdit}
            onChange={(e) =>
              onChange({ ...student, timezoneId: Number(e.target.value) as MockStudent['timezoneId'] })
            }
          >
            {TIME_ZONE_ID_LIST.map((id) => {
              const tz = getTimeZoneById(id);
              return tz ? (
                <option key={id} value={id}>
                  {formatTimeZoneOptionLabel(tz)}
                </option>
              ) : null;
            })}
          </AdaptiveSelect>
        </div>
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Status</label>
            <AdaptiveSelect
              className={styles.input}
              value={String(student.statusId)}
              readOnly={!canEdit}
              onChange={(e) =>
                onChange({
                  ...student,
                  statusId: Number(e.target.value) as MockStudent['statusId'],
                })
              }
            >
              {USER_ACCOUNT_STATUS_ID_LIST.map((id) => {
                const s = getUserAccountStatusById(id);
                return s ? (
                  <option key={id} value={id}>
                    {s.name}
                  </option>
                ) : null;
              })}
            </AdaptiveSelect>
          </div>
        ) : null}
        {!isStudentViewer ? (
          <div className={styles.fieldGroup}>
            <label className={styles.label}>Schedule type</label>
            <AdaptiveSelect
              className={styles.input}
              value={String(student.scheduleType)}
              readOnly={!canEdit}
              onChange={(e) =>
                onChange({ ...student, scheduleType: e.target.value === 'true' })
              }
            >
              <option value="true">Fixed schedule</option>
              <option value="false">Flexible schedule</option>
            </AdaptiveSelect>
          </div>
        ) : null}
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Calendar color (HEX)</label>
          <CalendarColorPicker
            value={student.color ?? ''}
            disabled={!canEdit}
            onChange={(nextHex) => onChange({ ...student, color: nextHex })}
          />
        </div>
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit} onClick={onSave}>
          Save student data
        </Button>
      </div>
    </SurfaceCard>
  );
}

export function StudentCalendarTab({ lessons }: { lessons: ScheduledLessonDto[] }) {
  const [query, setQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | ScheduledLessonDto['statusId']>('all');
  const viewerIana = getIanaForTimeZoneId(activeMockUser.timezoneId);

  const sortedLessons = useMemo(
    () =>
      [...lessons].sort(
        (a, b) => lessonStartUtc(a).getTime() - lessonStartUtc(b).getTime(),
      ),
    [lessons],
  );

  const filteredLessons = useMemo(
    () =>
      sortedLessons.filter((lesson) => {
        const normalizedQuery = query.trim().toLowerCase();
        const queryMatch =
          normalizedQuery.length === 0 ||
          lesson.title.toLowerCase().includes(normalizedQuery) ||
          lesson.teacherName.toLowerCase().includes(normalizedQuery);
        const statusMatch = statusFilter === 'all' || lesson.statusId === statusFilter;
        return queryMatch && statusMatch;
      }),
    [query, sortedLessons, statusFilter],
  );

  const [selectedLessonId, setSelectedLessonId] = useState(sortedLessons[0]?.id);

  if (!lessons.length) {
    return <EmptyStateCard title="No lessons yet" description="Plan a lesson in the Schedule tab." />;
  }

  const selectedLesson = useMemo(
    () => filteredLessons.find((lesson) => lesson.id === selectedLessonId) ?? filteredLessons[0] ?? null,
    [filteredLessons, selectedLessonId],
  );

  const statusLabel = (statusId: ScheduledLessonDto['statusId']) => {
    if (statusId === LESSON_STATUS.planned.id) return 'Planned';
    if (statusId === LESSON_STATUS.completed.id) return 'Completed';
    return 'Cancelled';
  };

  return (
    <div className={styles.lessonWorkspace}>
      <SurfaceCard className={styles.lessonListPane}>
        <div className={styles.lessonFilters}>
          <div className={styles.lessonSearchWrap}>
            <Search size={15} />
            <Field
              className={styles.lessonSearch}
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Search lessons or teacher..."
            />
          </div>
          <AdaptiveSelect
            className={styles.input}
            value={statusFilter}
            onChange={(event) => {
              const next = event.target.value;
              setStatusFilter(
                next === 'all' ? 'all' : (Number(next) as ScheduledLessonDto['statusId']),
              );
            }}
          >
            <option value="all">All statuses</option>
            <option value={LESSON_STATUS.planned.id}>Planned</option>
            <option value={LESSON_STATUS.completed.id}>Completed</option>
            <option value={LESSON_STATUS.cancelled.id}>Cancelled</option>
          </AdaptiveSelect>
        </div>

        <div className={styles.calendarList}>
          {filteredLessons.map((lesson) => (
            <button
              key={lesson.id}
              type="button"
              className={`${styles.calendarItem} ${selectedLesson?.id === lesson.id ? styles.calendarItemActive : ''}`}
              onClick={() => setSelectedLessonId(lesson.id)}
            >
              <div className={styles.calendarItemTop}>
                <div className={styles.calendarTitle}>{lesson.title}</div>
                <span
                  className={`${styles.lessonStatusTag} ${lesson.statusId === LESSON_STATUS.planned.id ? styles.lessonStatusPlanned : ''} ${lesson.statusId === LESSON_STATUS.completed.id ? styles.lessonStatusCompleted : ''} ${lesson.statusId === LESSON_STATUS.cancelled.id ? styles.lessonStatusCancelled : ''}`}
                >
                  {statusLabel(lesson.statusId)}
                </span>
              </div>
              <div className={styles.calendarMeta}>
                {lessonDateKeyInZone(lesson, viewerIana)} · {lessonStartTimeInZone(lesson, viewerIana)} ·{' '}
                {lesson.duration} min
              </div>
              <div className={styles.calendarMeta}>{lesson.teacherName}</div>
            </button>
          ))}
          {filteredLessons.length === 0 ? (
            <div className={styles.calendarEmpty}>No lessons match your filters.</div>
          ) : null}
        </div>
      </SurfaceCard>

      <SurfaceCard className={styles.lessonDetailPane}>
        {selectedLesson ? (
          <>
            <div className={styles.lessonDetailHeader}>
              <h3 className={styles.lessonDetailTitle}>{selectedLesson.title}</h3>
              <div className={styles.lessonDetailBadges}>
                <span
                  className={`${styles.lessonStatusTag} ${selectedLesson.statusId === LESSON_STATUS.planned.id ? styles.lessonStatusPlanned : ''} ${selectedLesson.statusId === LESSON_STATUS.completed.id ? styles.lessonStatusCompleted : ''} ${selectedLesson.statusId === LESSON_STATUS.cancelled.id ? styles.lessonStatusCancelled : ''}`}
                >
                  {statusLabel(selectedLesson.statusId)}
                </span>
              </div>
            </div>

            <div className={styles.lessonMetaGrid}>
              <div className={styles.lessonMetaItem}>
                <Calendar size={15} />
                <span>{lessonDateKeyInZone(selectedLesson, viewerIana)}</span>
              </div>
              <div className={styles.lessonMetaItem}>
                <Clock3 size={15} />
                <span>
                  {lessonStartTimeInZone(selectedLesson, viewerIana)} –{' '}
                  {lessonEndTimeInZone(selectedLesson, viewerIana)}
                </span>
              </div>
              <div className={styles.lessonMetaItem}>
                <UserRound size={15} />
                <span>{selectedLesson.teacherName}</span>
              </div>
            </div>

            <div className={styles.lessonSection}>
              <div className={styles.lessonSectionTitle}>Lesson plan</div>
              <p className={styles.lessonSectionBody}>
                {selectedLesson.lessonPlan || selectedLesson.notes || 'No lesson plan yet.'}
              </p>
            </div>

            <div className={styles.lessonSection}>
              <div className={styles.lessonSectionTitle}>Materials</div>
              {selectedLesson.materials && selectedLesson.materials.length > 0 ? (
                <div className={styles.lessonFilesList}>
                  {selectedLesson.materials.map((material) => (
                    <div key={material.id} className={styles.lessonFileRow}>
                      <FileText size={14} />
                      <span>{material.text || `${material.kind} material`}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <p className={styles.lessonSectionBody}>No materials added.</p>
              )}
            </div>

            <div className={styles.lessonSection}>
              <div className={styles.lessonSectionTitle}>Homework</div>
              <p className={styles.lessonSectionBody}>{selectedLesson.homework?.text || 'No homework assigned.'}</p>
            </div>

            <div className={styles.lessonSection}>
              <div className={styles.lessonSectionTitle}>
                <MessageSquareText size={14} />
                <span>Student response</span>
              </div>
              <p className={styles.lessonSectionBody}>
                {selectedLesson.studentResponse?.text || 'No student response yet.'}
              </p>
            </div>
          </>
        ) : (
          <div className={styles.calendarEmpty}>Pick a lesson from the list to see details.</div>
        )}
      </SurfaceCard>
    </div>
  );
}

export function StudentScheduleTab({
  canEdit,
  date,
  setDate,
  time,
  setTime,
  recurrence,
  setRecurrence,
  comment,
  setComment,
  onPlan,
}: {
  canEdit: boolean;
  date: string;
  setDate: (v: string) => void;
  time: string;
  setTime: (v: string) => void;
  recurrence: LessonRecurrence;
  setRecurrence: (v: LessonRecurrence) => void;
  comment: string;
  setComment: (v: string) => void;
  onPlan: () => void;
}) {
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Date</label>
          <Field type="date" className={styles.input} value={date} readOnly={!canEdit} onChange={(e) => setDate(e.target.value)} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Time</label>
          <Field type="time" className={styles.input} value={time} readOnly={!canEdit} onChange={(e) => setTime(e.target.value)} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Recurrence</label>
          <AdaptiveSelect className={styles.input} value={recurrence} readOnly={!canEdit} onChange={(e) => setRecurrence(e.target.value as LessonRecurrence)}>
            <option value="none">No repeat</option>
            <option value="weekly">Weekly</option>
            <option value="monthly">Monthly</option>
          </AdaptiveSelect>
        </div>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.label}>Comment</label>
        <Field as="textarea" className={`${styles.input} ${styles.notes}`} value={comment} readOnly={!canEdit} onChange={(e) => setComment(e.target.value)} rows={3} />
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit || !date || !time} onClick={onPlan}>
          Plan lesson
        </Button>
      </div>
    </SurfaceCard>
  );
}

